import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm uses an adaptive influence model where each node's selection probability dynamically changes based on both time-dependent travel efficiency and a continuously updated equilibrium state between node accessibility and congestion potential.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    influence_scores = {}
    total_distance = np.sum(distance_matrix)

    for node in unvisited_nodes:
        travel_efficiency = distance_matrix[current_node, node] / total_distance
        congestion_potential = sum(1 / (1 + distance_matrix[truck, node]) for truck in truck_nodes)
        accessibility = 1 / (1 + distance_matrix[current_node, node])

        influence_scores[node] = accessibility / (travel_efficiency + congestion_potential)

    next_node = max(influence_scores, key=influence_scores.get)

    return next_node
